/**
 * @param {unknown} value
 * @returns {boolean}
 */
function isPlainObject(value) {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

/**
 * Copy selected keys from a plain object.
 * @param {Record<string, unknown>} source
 * @param {string[]} keys
 * @returns {Record<string, unknown>}
 * @throws {TypeError} When source is not a plain object
 */
export function pickKeys(source, keys) {
  if (!isPlainObject(source)) {
    throw new TypeError('source must be a plain object');
  }
  const picked = {};
  for (const key of keys) {
    if (key in source) {
      picked[key] = source[key];
    }
  }
  return picked;
}

/**
 * Copy a plain object excluding listed keys.
 * @param {Record<string, unknown>} source
 * @param {string[]} keys
 * @returns {Record<string, unknown>}
 * @throws {TypeError} When source is not a plain object
 */
export function omitKeys(source, keys) {
  if (!isPlainObject(source)) {
    throw new TypeError('source must be a plain object');
  }
  const omitted = { ...source };
  for (const key of keys) {
    delete omitted[key];
  }
  return omitted;
}
